const SUPABASE_URL = 'https://hkqssbomrcbtfbdowtgj.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhrcXNzYm9tcmNidGZiZG93dGdqIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3Nzg3MTU1MywiZXhwIjoyMDkzNDQ3NTUzfQ.sIW3-eY1IVz1CuErVL9k_2IC9LX1nBS_S9wkT__RgoI';

const body = $input.first().json.body || $input.first().json;
if (!body.lead_email) throw new Error('Missing required field: lead_email');

return [{ json: {
  SUPABASE_URL,
  SUPABASE_KEY,
  lead_email: body.lead_email.toLowerCase().trim(),
  requesting_channel: body.requesting_channel || null,
  max_events: parseInt(body.max_events) || 20
}}];

const setup = $('Setup & Validate').first().json;
const rpcResult = $input.first().json;

// RPC always returns { lead: {...}|null, conversations: [...] } — never an empty array
const lead = rpcResult.lead || null;
const conversations = Array.isArray(rpcResult.conversations)
  ? [...rpcResult.conversations].reverse()  // RPC returns DESC; reverse to chronological
  : [];

const iconMap = { email: '[EMAIL]', linkedin: '[LINKEDIN]', voice: '[VOICE]', sms: '[SMS]' };

if (!lead) {
  return [{ json: {
    context_block: '(No prior conversation history found for this lead.)',
    lead: null, event_count: 0, overall_intent: 'unknown', lead_email: setup.lead_email
  }}];
}

if (conversations.length === 0) {
  const h = 'Lead: ' + (lead.full_name || lead.lead_email) + (lead.company ? ' (' + lead.company + ')' : '') + '\nOverall Intent: ' + (lead.overall_intent || 'unknown');
  return [{ json: {
    context_block: '=== Cross-Channel Conversation History ===\n' + h + '\n\n(No conversation history yet.)',
    lead, event_count: 0, overall_intent: lead.overall_intent || 'unknown', lead_email: setup.lead_email
  }}];
}

const intentUpdated = lead.overall_intent_updated_at ? new Date(lead.overall_intent_updated_at).toISOString().slice(0,10) : 'unknown';
const lines = [
  '=== Cross-Channel Conversation History ===',
  'Lead: ' + (lead.full_name || lead.lead_email) + (lead.company ? ' (' + lead.company + ')' : ''),
  'Overall Intent: ' + (lead.overall_intent || 'unknown') + ' (updated: ' + intentUpdated + ')',
  ''
];

if (setup.requesting_channel) {
  lines.unshift('You are replying on ' + setup.requesting_channel.toUpperCase() + '. Prior cross-channel context below.');
  lines.unshift('');
}

for (const conv of conversations) {
  const icon = iconMap[conv.channel] || '[?]';
  const dir = conv.direction === 'inbound' ? 'Inbound' : 'Outbound';
  const ts = new Date(conv.timestamp).toISOString().replace('T',' ').slice(0,16) + ' UTC';
  const content = (conv.content || '').length > 300 ? conv.content.slice(0,297) + '...' : (conv.content || '');
  const sender = conv.sender_name ? ' - ' + conv.sender_name : '';
  lines.push('[' + ts + '] ' + icon + ' ' + conv.channel.toUpperCase() + ' - ' + dir + sender);
  lines.push(content);
  if (conv.intent && conv.intent !== 'unknown') lines.push('Intent: ' + conv.intent);
  lines.push('');
}

return [{ json: {
  context_block: lines.join('\n'),
  lead, event_count: conversations.length,
  overall_intent: lead.overall_intent || 'unknown',
  lead_email: setup.lead_email
}}];
